const html = $input.first().json.htmlContent || "";
const chatId = $("Parse Command").item.json.chat_id;
const url = $("Parse Command").item.json.args;

// Extract title
let title = "";
const titleMatch = html.match(/<title>(.*?)<\/title>/i);
if (titleMatch) {
  title = titleMatch[1];
} else {
  const h1Match = html.match(/<h1[^>]*>(.*?)<\/h1>/i);
  if (h1Match) {
    title = h1Match[1].replace(/<[^>]*>/g, "");
  } else {
    title = "Untitled Article";
  }
}

// Strip HTML tags
const text = html.replace(/<script[^>]*>.*?<\/script>/gi, "")
  .replace(/<style[^>]*>.*?<\/style>/gi, "")
  .replace(/<[^>]+>/g, " ")
  .replace(/\s+/g, " ")
  .trim();

return [{ title, text, chat_id: chatId, url }];

