const q = $input.first().json;

if (!q.question || !q.options) {
  throw new Error(`Question data is missing. Received: ${JSON.stringify(q)}`);
}

let options = q.options;

if (typeof options === 'string') {
  options = JSON.parse(options);
}

const letters = ['A', 'B', 'C', 'D'];

const getOption = (letter, index) => {
  if (Array.isArray(options)) {
    return options[index];
  }

  return options[letter];
};

const cleanOption = (value) => {

  return String(value || '')

    .replace(/^[A-D][\)\.\:\-]\s*/i, '')

    .trim();

};

const questionNum = Number(q.questionIndex ?? 0) + 1;

const text =
  `Question ${questionNum}/5\n\n` +
  `${q.question}\n\n` +
  letters
    .map((letter, index) => `${letter}) ${cleanOption(getOption(letter, index))}`)
    .join('\n');

const inline_keyboard = letters.map((letter) => [
  {
    text: letter,
    callback_data: `answer:${q.quizSessionId}:${q.id}:${letter}`,
  },
]);

const payload = {
  chat_id: Number(q.userId),
  text,
  reply_markup: {
    inline_keyboard,
  },
};

return [
  {
    json: {
      chat_id: Number(q.userId),
      text,
      reply_markup: payload.reply_markup,
      body_json: JSON.stringify(payload),
    },
  },
];

