const data = $input.first().json;

const questions = data.questions || [];
const materialId = data.materialId;
const userId = data.userId;

if (!Array.isArray(questions) || questions.length === 0) {
  throw new Error('No questions found from Examiner Agent output');
}

const quizSessionId = `quiz-${Date.now()}`;

return questions.map((q, index) => {
  return {
    json: {
      quizSessionId,
      userId,
      materialId,
      question: q.question,
      options: JSON.stringify(q.options),
      correctAnswer: q.correctAnswer,
      explanation: q.explanation,
      questionIndex: index,
      userAnswer: '',
      isCorrect: false,
    },
  };
});

const q = $('Check More Questions').first().json;

if (!q.question || !q.options) {
  throw new Error(`Next question data is missing. Received: ${JSON.stringify(q)}`);
}

let options = q.options;

if (typeof options === 'string') {
  options = JSON.parse(options);
}

const letters = ['A', 'B', 'C', 'D'];

const getOption = (letter, index) => {
  if (Array.isArray(options)) {
    return options[index];
  }

  return options[letter];
};

const cleanOption = (value) => {
  return String(value || '')
    .replace(/^[A-D][\)\.\:\-]\s*/i, '')
    .trim();
};

const questionNum = Number(q.questionIndex ?? 0) + 1;

const text =
  `Question ${questionNum}/5\n\n` +
  `${q.question}\n\n` +
  letters
    .map((letter, index) => `${letter}) ${cleanOption(getOption(letter, index))}`)
    .join('\n');

const inline_keyboard = letters.map((letter) => [
  {
    text: letter,
    callback_data: `answer:${q.quizSessionId}:${q.id}:${letter}`,
  },
]);

const payload = {
  chat_id: Number(q.userId),
  text,
  reply_markup: {
    inline_keyboard,
  },
};

return [
  {
    json: {
      chat_id: Number(q.userId),
      text,
      reply_markup: payload.reply_markup,
      body_json: JSON.stringify(payload),
    },
  },
];

const answers = $input.all().map((item) => item.json);

const total = answers.length;

if (total === 0) {
  throw new Error('No answers found for score calculation');
}

const correct = answers.filter((answer) => {
  return answer.isCorrect === true || answer.isCorrect === 'true';
}).length;

const percentage = Math.round((correct / total) * 100);

const sortedAnswers = answers.sort(
  (a, b) => Number(a.questionIndex) - Number(b.questionIndex)
);

const details = sortedAnswers
  .map((answer, index) => {
    const isCorrect = answer.isCorrect === true || answer.isCorrect === 'true';
    const status = isCorrect ? '✅' : '❌';

    const feedback = answer.feedback || (isCorrect ? 'Correct.' : 'Incorrect.');

    let result =
      `${index + 1}. ${status} ${answer.question}
Your answer: ${answer.userAnswer || 'No answer'}
Correct answer: ${answer.correctAnswer}
Feedback: ${feedback}`;

    if (!isCorrect) {
      result += `\nExplanation: ${answer.explanation || 'No explanation provided.'}`;
    }

    return result;
  })
  .join('\n\n');

const chatId = Number($('Prepare AI Validation').first().json.chat_id);

const text =
  `🎯 Quiz Complete!\n\n` +
  `Score: ${percentage}%\n` +
  `Correct answers: ${correct}/${total}\n\n` +
  `Review:\n${details}\n\n` +
  `${percentage >= 80 ? '🌟 Excellent work!' : percentage >= 60 ? '👍 Good job!' : '📚 Keep studying!'}`;

const payload = {
  chat_id: chatId,
  text,
};

return [
  {
    json: {
      chat_id: chatId,
      total,
      correct,
      percentage,
      details,
      text,
      body_json: JSON.stringify(payload),
    },
  },
];

const T = {
  pickTopic: '📚 Select a topic for your quiz:',
  materialsCount: (count) =>
    `You have ${count} saved learning material${count === 1 ? '' : 's'}.`,
  noMaterials:
    '📭 No saved learning materials yet.\n\nSend /learn [URL] first to add a topic.',
};

const input = $input.first().json;

const chatId = Number(
  input.chat_id ||
  $('Parse Command').first().json.chat_id
);

const buttonRows = input.buttons || [];

const inline_keyboard = buttonRows
  .filter((row) => Array.isArray(row?.row?.buttons) && row.row.buttons.length > 0)
  .map((row) =>
    row.row.buttons.map((button) => ({
      text: String(button.text || 'Untitled material'),
      callback_data: String(button.additionalFields?.callback_data || ''),
    }))
  )
  .filter((row) => row.every((button) => button.callback_data));

let payload;

if (inline_keyboard.length === 0) {
  payload = {
    chat_id: chatId,
    text: T.noMaterials,
  };
} else {
  payload = {
    chat_id: chatId,
    text: `${T.pickTopic}\n\n${T.materialsCount(inline_keyboard.length)}`,
    reply_markup: {
      inline_keyboard,
    },
  };
}

return [
  {
    json: {
      chat_id: chatId,
      text: payload.text,
      reply_markup: payload.reply_markup,
      body_json: JSON.stringify(payload),
    },
  },
];

const materials = $input.all().map(item => item.json);
const chatId = materials[0].userId;

const buttons = materials.map(mat => ({
  row: {
    buttons: [{
      text: mat.title + " (" + mat.difficulty + ")",
      additionalFields: {
        callback_data: "quiz:" + mat.id
      }
    }]
  }
}));

return [{ chat_id: chatId, buttons }];

const input = $input.first().json;

const callbackData =
  input.callback_data ||
  input.callback_query?.data ||
  input.text ||
  '';

const parts = callbackData.split(':');

const action = parts[0] || '';

let materialId = '';
let quizSessionId = '';
let questionId = '';
let answer = '';

if (action === 'quiz') {
  // Example: quiz:4
  materialId = parts[1] || '';
}

if (action === 'answer') {
  // Example: answer:quiz-1778560000000:7:A
  quizSessionId = parts[1] || '';
  questionId = parts[2] || '';
  answer = parts[3] || '';
}

return [
  {
    json: {
      ...input,
      callback_data: callbackData,
      action,
      materialId,
      quizSessionId,
      questionId,
      answer,
      chat_id: input.chat_id,
      message_id: input.message_id,
    },
  },
];

const originalQuestion = $('Fetch Question').first().json;
const callback = $('Parse Callback').first().json;

const validation = $json.output || $json;

const selectedAnswer = validation.selectedAnswer || callback.answer;
const correctAnswer = validation.correctAnswer || originalQuestion.correctAnswer;

const isCorrect =
  validation.isCorrect === true ||
  validation.isCorrect === 'true';

const feedback =
  validation.feedback ||
  (isCorrect ? 'Correct.' : 'Incorrect.');

const explanation = isCorrect
  ? ''
  : (validation.explanation || originalQuestion.explanation || '');

return [
  {
    json: {
      quizSessionId: originalQuestion.quizSessionId,
      userId: originalQuestion.userId,
      materialId: originalQuestion.materialId,

      questionId: originalQuestion.id,
      question: originalQuestion.question,
      options: originalQuestion.options,
      questionIndex: originalQuestion.questionIndex,

      userAnswer: selectedAnswer,
      isCorrect,
      correctAnswer,

      feedback,
      explanation,

      chat_id: callback.chat_id,
      message_id: callback.message_id,
    },
  },
];
